/**
 * Axis configuration for the minimum value
 * @public
 */
export type MinScaleBoundary = number | 'data-min' | 'auto';
/**
 * Axis configuration for the maximum value
 * @public
 */
export type MaxScaleBoundary = number | 'data-max' | 'auto';
/**
 * Boundaries of an Axis
 * @internal
 */
export interface MinMaxConfig {
    min: MinScaleBoundary;
    max: MaxScaleBoundary;
}
